describe("E2E Agent Lifecycle", () => {
  it("spawns agent -> receives task -> completes -> terminates", async () => {
    const hive = await initHive();
    const agent = await hive.agentManager.spawnHeadlessAgent(profile, {
      prompt: "List files in current directory"
    });
    await waitForCompletion(agent.id, 30000);
    const result = await hive.agentManager.getAgentResult(agent.id);
    expect(result.status).toBe("completed");
    await hive.agentManager.terminateAgent(agent.id);
  });
});
