import { describe, it, expect, beforeEach } from "vitest";
import * as workflowEngine from "@zana/core/src/workflow-engine.ts";

describe("Workflow Engine", () => {
  describe("Condition Evaluation", () => {
    it("should evaluate simple conditions", () => {
      const result = workflowEngine.evaluateCondition(
        "ticket.priority === 'high'",
        { ticket: { priority: "high" } }
      );
      expect(result).toBe(true);
    });

    it("should handle complex conditions", () => {
      const result = workflowEngine.evaluateCondition(
        "ticket.status === 'done' && run.stepCount > 3",
        { 
          ticket: { status: "done" },
          run: { stepCount: 5 }
        }
      );
      expect(result).toBe(true);
    });

    it("should prevent code injection", () => {
      expect(() => workflowEngine.evaluateCondition(
        "require('fs').readFileSync('/etc/passwd')",
        {}
      )).toThrow();
    });
  });

  describe("Workflow Execution", () => {
    it("should execute simple workflow", async () => {
      const skill = {
        id: "test-workflow",
        name: "Test",
        steps: [
          { action: "log", message: "Step 1" },
          { action: "log", message: "Step 2" }
        ]
      };

      const run = await workflowEngine.executeWorkflow(skill);
      expect(run.status).toBe("running");
    });

    it("should enforce max concurrent runs", async () => {
      const skill = { id: "test", steps: [{ action: "sleep", duration: 5000 }] };

      const runs = await Promise.all([
        workflowEngine.executeWorkflow(skill),
        workflowEngine.executeWorkflow(skill),
        workflowEngine.executeWorkflow(skill),
        workflowEngine.executeWorkflow(skill) // Should fail
      ]);

      expect(runs[3].error).toBe("max_concurrent_runs");
    });

    it("should interpolate prompt templates", () => {
      const result = workflowEngine.interpolatePrompt(
        "Hello {{user.name}}, status: {{ticket.status}}",
        { 
          user: { name: "Alice" },
          ticket: { status: "done" }
        }
      );

      expect(result).toBe("Hello Alice, status: done");
    });
  });

  describe("Error Recovery", () => {
    it("should handle step timeout", async () => {
      const skill = {
        id: "timeout-test",
        steps: [{ action: "long-running", timeout: 100 }]
      };

      const run = await workflowEngine.executeWorkflow(skill);
      await new Promise(r => setTimeout(r, 200));

      const status = workflowEngine.loadRun(run.id);
      expect(status.error).toContain("timeout");
    });

    it("should resume workflow after restart", async () => {
      const skill = { id: "resume-test", steps: [
        { action: "step1" },
        { action: "step2" },
        { action: "step3" }
      ]};

      const run = await workflowEngine.executeWorkflow(skill);

      // Simulate crash after step 1
      await workflowEngine.shutdown();
      await workflowEngine.init();

      const resumed = await workflowEngine.resumeWorkflow(run.id);
      expect(resumed.currentStep).toBeGreaterThan(0);
    });
  });
});
