import { describe, it, expect, beforeEach, afterEach, vi } from "vitest";
import * as agentManager from "@zana/core/src/agent-manager.ts";
import * as profileStore from "@zana/core/src/profile-store.ts";

describe("Agent Manager", () => {
  beforeEach(() => {
    agentManager.init();
    profileStore.registerProfile({
      id: "test",
      displayName: "Test Agent",
      model: "claude-sonnet-4-6"
    });
  });

  afterEach(async () => {
    const agents = agentManager.listAgents();
    for (const agent of agents) {
      await agentManager.terminateAgent(agent.id);
    }
  });

  describe("Resource Checks", () => {
    it("should prevent spawn when CPU load is high", () => {
      vi.spyOn(os, "loadavg").mockReturnValue([16, 10, 8]); // High load
      const profile = profileStore.getProfile("test");

      expect(() => agentManager.spawnHeadlessAgent(profile, {}))
        .toThrow(/CPU load too high/);
    });

    it("should prevent spawn when memory is low", () => {
      vi.spyOn(os, "freemem").mockReturnValue(100 * 1024 * 1024); // 100MB
      vi.spyOn(os, "totalmem").mockReturnValue(16 * 1024 * 1024 * 1024); // 16GB

      expect(() => agentManager.spawnHeadlessAgent(profile, {}))
        .toThrow(/memory too low/);
    });
  });

  describe("Concurrency", () => {
    it("should enforce max concurrent agents limit", async () => {
      const max = agentManager.getMaxConcurrentAgents();
      const spawns = [];

      for (let i = 0; i < max + 1; i++) {
        spawns.push(agentManager.spawnHeadlessAgent(profile, { 
          prompt: `Task ${i}` 
        }));
      }

      await expect(Promise.all(spawns)).rejects.toThrow(/max agents/);
    });

    it("should handle concurrent terminations", async () => {
      const agents = await Promise.all([
        agentManager.spawnHeadlessAgent(profile, { prompt: "1" }),
        agentManager.spawnHeadlessAgent(profile, { prompt: "2" }),
        agentManager.spawnHeadlessAgent(profile, { prompt: "3" })
      ]);

      await Promise.all(agents.map(a => agentManager.terminateAgent(a.agentId)));

      expect(agentManager.listAgents().length).toBe(0);
    });
  });

  describe("State Management", () => {
    it("should track agent state transitions correctly", async () => {
      const states = [];
      agentManager.onChange((snapshot) => {
        states.push(snapshot.map(a => a.state));
      });

      const agent = await agentManager.spawnHeadlessAgent(profile, { 
        prompt: "test" 
      });

      await new Promise(r => setTimeout(r, 1000));

      expect(states).toContain(["spawning"]);
      expect(states).toContain(["active"]);
    });
  });

  describe("Error Recovery", () => {
    it("should cleanup zombie processes", async () => {
      const agent = await agentManager.spawnHeadlessAgent(profile, {});

      // Kill process directly (simulate crash)
      process.kill(agent.pid, "SIGKILL");

      await new Promise(r => setTimeout(r, 5000));

      const found = agentManager.listAgents().find(a => a.id === agent.agentId);
      expect(found?.state).toBe("crashed");
    });
  });
});

import { describe, it, expect, beforeEach } from "vitest";
import * as goapPlanner from "@zana/core/src/goap-planner.ts";

describe("GOAP Planner", () => {
  beforeEach(() => {
    goapPlanner.init();
  });

  describe("Goal Parsing", () => {
    it("should parse goal state from keywords", () => {
      const plan = goapPlanner.createPlan("implement feature and write tests");
      expect(plan.goalState).toMatchObject({
        codeWritten: true,
        testsWritten: true
      });
    });

    it("should handle complex goal descriptions", () => {
      const plan = goapPlanner.createPlan(
        "analyze requirements, design architecture, implement code, write comprehensive tests"
      );
      expect(plan.goalState).toMatchObject({
        requirementsAnalyzed: true,
        architectureDesigned: true,
        codeWritten: true,
        testsWritten: true
      });
    });
  });

  describe("Action Planning", () => {
    it("should generate valid action sequence", () => {
      const plan = goapPlanner.createPlan("implement feature");
      expect(plan.actions.length).toBeGreaterThan(0);
      expect(plan.actions[0].id).toBe("analyze-requirements");
    });

    it("should handle custom actions", () => {
      goapPlanner.registerAction({
        id: "custom-validate",
        preconditions: { testsWritten: true },
        effects: { validated: true },
        profileId: "validator",
        cost: 2
      });

      const plan = goapPlanner.createPlan("implement and validate feature");
      expect(plan.actions.some(a => a.id === "custom-validate")).toBe(true);
    });

    it("should optimize for lowest cost path", () => {
      const plan = goapPlanner.createPlan("write code");
      const totalCost = plan.actions.reduce((sum, a) => sum + a.cost, 0);
      expect(totalCost).toBeLessThan(20); // Sanity check
    });
  });

  describe("Edge Cases", () => {
    it("should handle circular dependencies", () => {
      goapPlanner.registerAction({
        id: "a",
        preconditions: { b: true },
        effects: { a: true },
        profileId: "test"
      });
      goapPlanner.registerAction({
        id: "b",
        preconditions: { a: true },
        effects: { b: true },
        profileId: "test"
      });

      expect(() => goapPlanner.createPlan("circular goal"))
        .toThrow(/no valid plan/);
    });

    it("should handle impossible goals", () => {
      const plan = goapPlanner.createPlan("impossible goal with no actions");
      expect(plan.error).toBeDefined();
    });
  });

  describe("Plan Execution", () => {
    it("should execute plan steps sequentially", async () => {
      const plan = goapPlanner.createPlan("implement feature");
      const execution = await goapPlanner.executePlan(plan.id);

      expect(execution.status).toBe("running");
      expect(execution.currentStep).toBe(0);
    });

    it("should handle step failure and retry", async () => {
      // Mock agent spawn failure
      const plan = goapPlanner.createPlan("test goal");
      // Force failure on step 2
      await goapPlanner.executePlan(plan.id);

      // Should have retried and marked as failed
    });
  });
});

import { describe, it, expect, beforeEach, afterEach } from "vitest";
import * as vectorMemory from "@zana/core/src/vector-memory.ts";
import * as fs from "node:fs";

describe("Vector Memory", () => {
  beforeEach(async () => {
    await vectorMemory.init();
  });

  afterEach(async () => {
    await vectorMemory.shutdown();
  });

  describe("Storage", () => {
    it("should store and retrieve memory entry", async () => {
      const id = await vectorMemory.store({
        content: "test memory content",
        tier: "working",
        metadata: { source: "test" }
      });

      expect(id).toBeDefined();
      const entries = vectorMemory.search({ content: "test memory" });
      expect(entries.length).toBeGreaterThan(0);
      expect(entries[0].content).toContain("test memory");
    });

    it("should enforce tier TTL", async () => {
      const id = await vectorMemory.store({
        content: "short-lived memory",
        tier: "working" // 1 hour TTL
      });

      // Fast-forward time
      vi.advanceTimersByTime(61 * 60 * 1000);
      await vectorMemory.expire();

      const results = vectorMemory.search({ content: "short-lived" });
      expect(results.length).toBe(0);
    });
  });

  describe("Search", () => {
    it("should rank results by similarity", async () => {
      await vectorMemory.store({ content: "javascript programming" });
      await vectorMemory.store({ content: "typescript development" });
      await vectorMemory.store({ content: "python scripting" });

      const results = vectorMemory.search({ 
        content: "typescript javascript", 
        limit: 2 
      });

      expect(results[0].content).toContain("typescript");
      expect(results[1].content).toContain("javascript");
    });

    it("should handle empty query", () => {
      const results = vectorMemory.search({ content: "" });
      expect(results).toEqual([]);
    });

    it("should filter by metadata", async () => {
      await vectorMemory.store({ 
        content: "test1", 
        metadata: { type: "code" } 
      });
      await vectorMemory.store({ 
        content: "test2", 
        metadata: { type: "docs" } 
      });

      const results = vectorMemory.search({ 
        content: "test", 
        metadata: { type: "code" } 
      });

      expect(results.length).toBe(1);
      expect(results[0].metadata.type).toBe("code");
    });
  });

  describe("Performance", () => {
    it("should handle 10k entries efficiently", async () => {
      const start = Date.now();

      for (let i = 0; i < 10000; i++) {
        await vectorMemory.store({ 
          content: `entry ${i} with some text content` 
        });
      }

      const storeTime = Date.now() - start;
      expect(storeTime).toBeLessThan(30000); // 30s for 10k entries

      const searchStart = Date.now();
      const results = vectorMemory.search({ content: "entry 5000", limit: 10 });
      const searchTime = Date.now() - searchStart;

      expect(searchTime).toBeLessThan(1000); // <1s search
      expect(results.length).toBeGreaterThan(0);
    });
  });

  describe("Error Handling", () => {
    it("should handle corrupted vocabulary file", async () => {
      fs.writeFileSync(vectorMemory.VOCAB_PATH, "{ corrupt");

      await expect(vectorMemory.init()).rejects.toThrow();
    });

    it("should prevent oversized entries", () => {
      const huge = "x".repeat(10 * 1024 * 1024); // 10MB

      expect(() => vectorMemory.store({ content: huge }))
        .toThrow(/entry too large/);
    });
  });
});

